import{_ as a,c as o,o as i,a1 as r}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Acuerdo de Usuario: Reglas del Servicio | OpenCodeDocs","description":"Conoce las reglas de uso del servicio de OpenCodeDocs, la propiedad de los derechos de autor y las cláusulas de exención de responsabilidad, definiendo los derechos y obligaciones de ambas partes.","frontmatter":{"title":"Acuerdo de Usuario: Reglas del Servicio | OpenCodeDocs","sidebarTitle":"Entiende las reglas en 5 minutos","subtitle":"Acuerdo de Usuario: Reglas del Servicio","description":"Conoce las reglas de uso del servicio de OpenCodeDocs, la propiedad de los derechos de autor y las cláusulas de exención de responsabilidad, definiendo los derechos y obligaciones de ambas partes."},"headers":[],"relativePath":"es/terms.md","filePath":"es/terms.md"}'),s={name:"es/terms.md"};function n(d,e,t,l,c,u){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="acuerdo-de-servicio-al-usuario" tabindex="-1">Acuerdo de Servicio al Usuario <a class="header-anchor" href="#acuerdo-de-servicio-al-usuario" aria-label="Permalink to &quot;Acuerdo de Servicio al Usuario&quot;">​</a></h1><p>Última actualización: 2026-01-01 Fecha de entrada en vigor: 2026-01-01</p><p>¡Bienvenido a OpenCodeDocs! Antes de utilizar nuestros servicios, lea cuidadosamente este Acuerdo de Servicio al Usuario (en adelante, &quot;este Acuerdo&quot;). El uso de nuestros servicios implica que acepta estar sujeto a los términos de este Acuerdo.</p><h2 id="_1-descripcion-del-servicio" tabindex="-1">1. Descripción del Servicio <a class="header-anchor" href="#_1-descripcion-del-servicio" aria-label="Permalink to &quot;1. Descripción del Servicio&quot;">​</a></h2><p>OpenCodeDocs es una plataforma abierta centrada en tutoriales de herramientas de IA que ofrece los siguientes servicios:</p><ul><li><strong>Contenido de tutoriales</strong>: Tutoriales de uso de herramientas de IA de código abierto (como Claude Code, Cursor, LangChain, etc.)</li><li><strong>Validación de código</strong>: Verifica automáticamente la ejecutabilidad del código en los tutoriales basándose en repositorios de código fuente</li><li><strong>Funciones de comunidad</strong>: Los usuarios pueden participar en la contribución y discusión de contenido a través de GitHub</li></ul><p>Nos reservamos el derecho de modificar, suspender o terminar parcial o totalmente los servicios en cualquier momento sin previo aviso.</p><h2 id="_2-registro-y-gestion-de-cuentas" tabindex="-1">2. Registro y Gestión de Cuentas <a class="header-anchor" href="#_2-registro-y-gestion-de-cuentas" aria-label="Permalink to &quot;2. Registro y Gestión de Cuentas&quot;">​</a></h2><h3 id="condiciones-de-registro" tabindex="-1">Condiciones de Registro <a class="header-anchor" href="#condiciones-de-registro" aria-label="Permalink to &quot;Condiciones de Registro&quot;">​</a></h3><ul><li>Debe tener al menos 16 años de edad (o la edad legalmente exigida en su región)</li><li>Proporcionar información de registro precisa y veraz</li><li>Cada usuario solo puede registrar una cuenta</li></ul><h3 id="seguridad-de-la-cuenta" tabindex="-1">Seguridad de la Cuenta <a class="header-anchor" href="#seguridad-de-la-cuenta" aria-label="Permalink to &quot;Seguridad de la Cuenta&quot;">​</a></h3><ul><li>Es su responsabilidad proteger las credenciales de su cuenta y no compartirlas con otros</li><li>Si descubre que su cuenta ha sido comprometida, contáctenos de inmediato</li><li>Usted asume la responsabilidad por las pérdidas causadas por una gestión inadecuada de la cuenta</li></ul><h3 id="cancelacion-de-cuenta" tabindex="-1">Cancelación de Cuenta <a class="header-anchor" href="#cancelacion-de-cuenta" aria-label="Permalink to &quot;Cancelación de Cuenta&quot;">​</a></h3><p>Puede solicitar la cancelación de su cuenta en cualquier momento. Tras la cancelación, sus datos personales se eliminarán dentro de 30 días, pero el contenido publicado públicamente podría permanecer.</p><h2 id="_3-normas-de-comportamiento-del-usuario" tabindex="-1">3. Normas de Comportamiento del Usuario <a class="header-anchor" href="#_3-normas-de-comportamiento-del-usuario" aria-label="Permalink to &quot;3. Normas de Comportamiento del Usuario&quot;">​</a></h2><p>Al utilizar esta plataforma, acepta no realizar las siguientes actividades:</p><ul><li>Publicar contenido ilegal, dañino, amenazante, hostigante, difamatorio o que infrinja los derechos de otros</li><li>Hacerse pasar por otros o proporcionar información falsa sobre su identidad</li><li>Acceder sin autorización a cuentas o sistemas de otros usuarios</li><li>Interferir o interrumpir el funcionamiento normal del servicio</li><li>Utilizar herramientas automatizadas para extraer contenido a gran escala (excluyendo el uso razonable de la API)</li><li>Utilizar el contenido de los tutoriales con fines comerciales sin cumplir con el acuerdo de licencia</li></ul><h2 id="_4-derechos-de-propiedad-intelectual" tabindex="-1">4. Derechos de Propiedad Intelectual <a class="header-anchor" href="#_4-derechos-de-propiedad-intelectual" aria-label="Permalink to &quot;4. Derechos de Propiedad Intelectual&quot;">​</a></h2><h3 id="explicacion-de-licencias-de-codigo-abierto" tabindex="-1">Explicación de Licencias de Código Abierto <a class="header-anchor" href="#explicacion-de-licencias-de-codigo-abierto" aria-label="Permalink to &quot;Explicación de Licencias de Código Abierto&quot;">​</a></h3><ul><li><strong>Contenido de tutoriales</strong>: Adopta el acuerdo <a href="https://creativecommons.org/licenses/by-nc-sa/4.0/" target="_blank" rel="noreferrer">CC-BY-NC-SA 4.0</a>, que permite el uso compartido y la adaptación no comercial, pero requiere atribución y compartir bajo la misma licencia</li><li><strong>Construcción del sitio web</strong>: Este proyecto se basa en <a href="https://vitepress.dev/" target="_blank" rel="noreferrer">VitePress</a> y sigue el acuerdo MIT</li><li><strong>Contribuciones de usuario</strong>: El contenido que envíe está autorizado por defecto para que la plataforma lo use cumpliendo con los acuerdos anteriores</li></ul><p>Las marcas comerciales, logotipos y otros elementos de identificación de marca de OpenCodeDocs están protegidos por ley y no pueden utilizarse sin autorización.</p><h2 id="_5-declaracion-de-exencion-de-responsabilidad" tabindex="-1">5. Declaración de Exención de Responsabilidad <a class="header-anchor" href="#_5-declaracion-de-exencion-de-responsabilidad" aria-label="Permalink to &quot;5. Declaración de Exención de Responsabilidad&quot;">​</a></h2><ul><li><strong>Interrupción del servicio</strong>: No garantizamos que el servicio sea continuo o libre de errores. No nos hacemos responsables de las interrupciones del servicio causadas por mantenimiento, actualizaciones o fuerza mayor</li><li><strong>Precisión del contenido</strong>: El contenido de los tutoriales es solo para referencia; no garantizamos su disponibilidad en todos los entornos</li><li><strong>Riesgos de uso del código</strong>: Ejecuta el código de los tutoriales bajo su propio riesgo; recomendamos probarlo en un entorno aislado</li><li><strong>Enlaces de terceros</strong>: Este sitio puede contener enlaces a sitios web de terceros; no somos responsables de su contenido</li></ul><h2 id="_6-modificacion-del-acuerdo" tabindex="-1">6. Modificación del Acuerdo <a class="header-anchor" href="#_6-modificacion-del-acuerdo" aria-label="Permalink to &quot;6. Modificación del Acuerdo&quot;">​</a></h2><p>Podemos modificar este acuerdo ocasionalmente. El acuerdo modificado se publicará en el sitio web y se le notificará de las siguientes maneras:</p><ul><li>Anuncio en una posición destacada del sitio web</li><li>Enviar notificación por correo electrónico registrado (si corresponde)</li></ul><p>Continuar usando nuestros servicios implica que acepta el acuerdo modificado. Si no está de acuerdo con las modificaciones, deje de utilizar el servicio.</p><h2 id="_7-resolucion-de-controversias" tabindex="-1">7. Resolución de Controversias <a class="header-anchor" href="#_7-resolucion-de-controversias" aria-label="Permalink to &quot;7. Resolución de Controversias&quot;">​</a></h2><ul><li><strong>Ley aplicable</strong>: Este acuerdo se rige por las leyes de la República Popular China</li><li><strong>Resolución de controversias</strong>: Ambas partes deben resolver las controversias mediante negociación amistosa; si la negociación falla, cualquiera de las partes puede presentar una demanda ante el tribunal del pueblo con jurisdicción en el lugar donde se encuentra el acusado</li></ul><h2 id="_8-informacion-de-contacto" tabindex="-1">8. Información de Contacto <a class="header-anchor" href="#_8-informacion-de-contacto" aria-label="Permalink to &quot;8. Información de Contacto&quot;">​</a></h2><p>Si tiene alguna pregunta sobre este acuerdo, contáctenos:</p><ul><li><strong>Correo electrónico</strong>: <a href="mailto:vbgatecom@gmail.com" target="_blank" rel="noreferrer">vbgatecom@gmail.com</a></li><li><strong>GitHub</strong>: <a href="https://github.com/vbgate/opencodedocs" target="_blank" rel="noreferrer">vbgate/opencodedocs</a></li></ul>',32)])])}const g=a(s,[["render",n]]);export{m as __pageData,g as default};
